document.addEventListener("DOMContentLoaded",function(){var e=document.getElementById("simple-view"),t=document.getElementById("detail-view"),i=document.getElementById("timeline"),s=document.querySelectorAll(".timeline-item");e.addEventListener("click",function(){i.classList.add("simple-view"),e.classList.add("active"),t.classList.remove("active")}),t.addEventListener("click",function(){i.classList.remove("simple-view"),t.classList.add("active"),e.classList.remove("active")}),(s=Array.from(s)).sort(function(e,t){e=new Date(e.dataset.date);return new Date(t.dataset.date)-e}),s.forEach(function(e){return i.appendChild(e)}),i.classList.remove("simple-view"),t.classList.add("active"),e.classList.remove("active")});